// Static assets -- cache for 1 year (immutable content-hashed files)
app.use('/assets', express.static('public', {
  maxAge: '1y',
  immutable: true,
}));

// API responses -- stale-while-revalidate pattern
router.get('/api/posts', async (req, res) => {
  const posts = await getPublishedPosts();

  res.set('Cache-Control', 'public, max-age=60, stale-while-revalidate=300');
  // Browser uses cached response for 60s
  // After 60s, serves stale while fetching fresh data in background
  // After 300s, must wait for fresh response

  res.json({ data: posts });
});

// Private data -- never cache
router.get('/api/me', authMiddleware, async (req, res) => {
  res.set('Cache-Control', 'private, no-store');
  res.json({ data: req.user });
});
